detailed_optimizations.code_changes:
将
for (i=0;i<M;i++)
  for (j=0;j<N;j++) {
    for (k=i+1;k<M;k++)
      B[i][j] += A[k][i] * B[k][j];
    B[i][j] *= alpha;
  }
改为
for (i=0;i<M;i++) {
  for (k=i+1;k<M;k++) {
    DATA_TYPE aik = A[k][i];
    #pragma omp simd
    for (j=0;j<N;j++)
      B[i][j] += aik * B[k][j];
  }
  #pragma omp simd
  for (j=0;j<N;j++)
    B[i][j] *= alpha;
}
这样固定 aik 后沿整行 j 扫描，可让编译器对 j 维做 SIMD，减少重复加载 A[k][i]。

在 k-j 顺序基础上，对 j 做块化，例如 JB=32/64：
for (i=0;i<M;i++) {
  for (jj=0;jj<N;jj+=JB) {
    int jend = min(jj+JB,N);
    for (k=i+1;k<M;k++) {
      DATA_TYPE aik = A[k][i];
      #pragma omp simd
      for (j=jj;j<jend;j++)
        B[i][j] += aik * B[k][j];
    }
    #pragma omp simd
    for (j=jj;j<jend;j++)
      B[i][j] *= alpha;
  }
}
若使用 AVX2/AVX-512，可进一步手写 intrinsic，对 B[i][j:j+VL-1] 和 B[k][j:j+VL-1] 做向量 FMA。

由于每个 i 的 B[i][j] 仅被该 i 写入，而不同 j 列彼此独立，可在固定 i 时并行 j 块：
for (i=0;i<M;i++) {
  for (k=i+1;k<M;k++) {
    DATA_TYPE aik = A[k][i];
    #pragma omp parallel for schedule(static)
    for (j=0;j<N;j++)
      B[i][j] += aik * B[k][j];
  }
  #pragma omp parallel for schedule(static)
  for (j=0;j<N;j++)
    B[i][j] *= alpha;
}
更优方式是对 j 分块后在外层并行，减少每个 k 上的线程启动开销：
for (i=0;i<M;i++) {
  #pragma omp parallel for private(k,j) schedule(static)
  for (jj=0;jj<N;jj+=JB) {
    for (k=i+1;k<M;k++) {
      DATA_TYPE aik = A[k][i];
      for (j=jj;j<min(jj+JB,N);j++)
        B[i][j] += aik * B[k][j];
    }
    for (j=jj;j<min(jj+JB,N);j++)
      B[i][j] *= alpha;
  }
}

当 N 很大时，可将 B 的列维分块，使 B[i][jj:jj+JB] 与 B[k][jj:jj+JB] 常驻 L1/L2。进一步可将当前输出行 B[i][jj:jj+JB] 先拷入局部缓冲区 accum[JB]，完成所有 k 累加后再写回：
for (i=0;i<M;i++)
  for (jj=0;jj<N;jj+=JB) {
    DATA_TYPE accum[JB];
    for (j=jj;j<jend;j++) accum[j-jj]=B[i][j];
    for (k=i+1;k<M;k++) {
      DATA_TYPE aik=A[k][i];
      #pragma omp simd
      for (j=jj;j<jend;j++)
        accum[j-jj] += aik * B[k][j];
    }
    #pragma omp simd
    for (j=jj;j<jend;j++)
      B[i][j] = alpha * accum[j-jj];
  }
这样减少对 B[i][j] 的反复读写，提升寄存器/L1 复用。

用供应商 BLAS 替换手写 kernel，例如 MKL/OpenBLAS/BLIS 的 TRMM：
cblas_dtrmm(CblasRowMajor, CblasLeft, CblasLower, CblasTrans, CblasUnit, m, n, alpha, &A[0][0], M, &B[0][0], N);
若库对 row-major 支持较弱，可转置/改列主序存储后调用原生高性能实现。

将 kernel 参数改为扁平 1D 指针并添加 restrict/assume_aligned，减少别名分析障碍；把常量提取到局部变量；保留 j 为内层循环以匹配行主序。示例：

void kernel_fdtd_2d_opt(int tmax, int nx, int ny,
    DATA_TYPE * __restrict ex,
    DATA_TYPE * __restrict ey,
    DATA_TYPE * __restrict hz,
    DATA_TYPE * __restrict fict) {
  const DATA_TYPE c1 = SCALAR_VAL(0.5);
  const DATA_TYPE c2 = SCALAR_VAL(0.7);
  for (int t = 0; t < tmax; ++t) {
    DATA_TYPE ft = fict[t];
    DATA_TYPE * __restrict ey0 = ey;
    #pragma omp simd
    for (int j = 0; j < ny; ++j) ey0[j] = ft;

    for (int i = 1; i < nx; ++i) {
      DATA_TYPE * __restrict ey_i   = ey + (size_t)i * ny;
      DATA_TYPE * __restrict hz_i   = hz + (size_t)i * ny;
      DATA_TYPE * __restrict hz_im1 = hz + (size_t)(i - 1) * ny;
      #pragma omp simd
      for (int j = 0; j < ny; ++j)
        ey_i[j] -= c1 * (hz_i[j] - hz_im1[j]);
    }

    for (int i = 0; i < nx; ++i) {
      DATA_TYPE * __restrict ex_i = ex + (size_t)i * ny;
      DATA_TYPE * __restrict hz_i = hz + (size_t)i * ny;
      #pragma omp simd
      for (int j = 1; j < ny; ++j)
        ex_i[j] -= c1 * (hz_i[j] - hz_i[j - 1]);
    }

    for (int i = 0; i < nx - 1; ++i) {
      DATA_TYPE * __restrict hz_i   = hz + (size_t)i * ny;
      DATA_TYPE * __restrict ex_i   = ex + (size_t)i * ny;
      DATA_TYPE * __restrict ey_i   = ey + (size_t)i * ny;
      DATA_TYPE * __restrict ey_ip1 = ey + (size_t)(i + 1) * ny;
      #pragma omp simd
      for (int j = 0; j < ny - 1; ++j)
        hz_i[j] -= c2 * (ex_i[j + 1] - ex_i[j] + ey_ip1[j] - ey_i[j]);
    }
  }
}

同时建议编译选项使用 -O3 -march=native -ffast-math（若允许数值语义放宽）并检查向量化报告。

对 ey/ex/hz 三个阶段采用块化处理，使相邻行的 hz、ey、ex 更可能驻留在 LLC/L2 中。由于 hz 更新依赖 ex[i][j+1] 和 ey[i+1][j]，推荐按 i 方向分块，必要时结合 j 方向块。示例框架：

const int Bi = 32;
for (int t = 0; t < tmax; ++t) {
  #pragma omp simd
  for (int j = 0; j < ny; ++j) ey[j] = fict[t];

  for (int ii = 1; ii < nx; ii += Bi) {
    int iend = (ii + Bi < nx) ? ii + Bi : nx;
    for (int i = ii; i < iend; ++i)
      #pragma omp simd
      for (int j = 0; j < ny; ++j)
        ey[i*ny + j] -= 0.5 * (hz[i*ny + j] - hz[(i-1)*ny + j]);
  }

  for (int ii = 0; ii < nx; ii += Bi) {
    int iend = (ii + Bi < nx) ? ii + Bi : nx;
    for (int i = ii; i < iend; ++i)
      #pragma omp simd
      for (int j = 1; j < ny; ++j)
        ex[i*ny + j] -= 0.5 * (hz[i*ny + j] - hz[i*ny + j - 1]);
  }

  for (int ii = 0; ii < nx - 1; ii += Bi) {
    int iend = (ii + Bi < nx - 1) ? ii + Bi : nx - 1;
    for (int i = ii; i < iend; ++i)
      #pragma omp simd
      for (int j = 0; j < ny - 1; ++j)
        hz[i*ny + j] -= 0.7 * (ex[i*ny + j + 1] - ex[i*ny + j] + ey[(i+1)*ny + j] - ey[i*ny + j]);
  }
}

Bi 需要通过 profiling 调优，通常 16/32/64 行较合适。

时间步 t 不能并行，但每个 t 内的三个空间更新阶段可分别并行。建议在每个阶段使用 #pragma omp parallel for schedule(static)，并保留阶段间隐式 barrier 以满足依赖。示例：

for (int t = 0; t < tmax; ++t) {
  DATA_TYPE ft = fict[t];
  #pragma omp parallel for schedule(static)
  for (int j = 0; j < ny; ++j)
    ey[j] = ft;

  #pragma omp parallel for schedule(static)
  for (int i = 1; i < nx; ++i)
    for (int j = 0; j < ny; ++j)
      ey[i*ny + j] -= 0.5 * (hz[i*ny + j] - hz[(i-1)*ny + j]);

  #pragma omp parallel for schedule(static)
  for (int i = 0; i < nx; ++i)
    for (int j = 1; j < ny; ++j)
      ex[i*ny + j] -= 0.5 * (hz[i*ny + j] - hz[i*ny + j - 1]);

  #pragma omp parallel for schedule(static)
  for (int i = 0; i < nx - 1; ++i)
    for (int j = 0; j < ny - 1; ++j)
      hz[i*ny + j] -= 0.7 * (ex[i*ny + j + 1] - ex[i*ny + j] + ey[(i+1)*ny + j] - ey[i*ny + j]);
}

若线程创建开销明显，可将 parallel 区域外提：#pragma omp parallel { for(t...) { #pragma omp for ... } }。

将 /9.0 改为乘以预计算常量 inv9；为数组指针提供 restrict/assume_aligned；将行指针提取到局部变量以减少地址计算。例如：

const DATA_TYPE inv9 = (DATA_TYPE)1.0 / (DATA_TYPE)9.0;
for (t = 0; t < tsteps; ++t) {
  for (i = 1; i < n - 1; ++i) {
    DATA_TYPE * __restrict rowm = A[i-1];
    DATA_TYPE * __restrict row  = A[i];
    DATA_TYPE * __restrict rowp = A[i+1];
    for (j = 1; j < n - 1; ++j) {
      row[j] = (rowm[j-1] + rowm[j] + rowm[j+1]
              + row [j-1] + row [j] + row [j+1]
              + rowp[j-1] + rowp[j] + rowp[j+1]) * inv9;
    }
  }
}

若使用平坦数组，可进一步写成 DATA_TYPE * __restrict A 并手工索引 idx=i*n+j。

对 i/j 做二维 tiling，使工作集更好驻留在 L1/L2。示例：

for (t = 0; t < tsteps; ++t)
  for (ii = 1; ii < n-1; ii += Ti)
    for (jj = 1; jj < n-1; jj += Tj)
      for (i = ii; i < min(ii+Ti, n-1); ++i) {
        DATA_TYPE *rowm = A[i-1], *row = A[i], *rowp = A[i+1];
        for (j = jj; j < min(jj+Tj, n-1); ++j)
          row[j] = (rowm[j-1]+rowm[j]+rowm[j+1]+
                    row[j-1]+row[j]+row[j+1]+
                    rowp[j-1]+rowp[j]+rowp[j+1]) * inv9;
      }

Ti/Tj 需按 cache 调优，典型可从 32x64、64x64 开始。注意该优化主要改善 cache/TLB 行为，不改变依赖方向。

在 j 方向维护 3 行的滑动窗口，减少重复加载和地址计算。示意：

for (i = 1; i < n-1; ++i) {
  DATA_TYPE *rowm = A[i-1], *row = A[i], *rowp = A[i+1];
  DATA_TYPE a0=rowm[0], a1=rowm[1];
  DATA_TYPE b0=row[0],  b1=row[1];
  DATA_TYPE c0=rowp[0], c1=rowp[1];
  for (j = 1; j < n-1; ++j) {
    DATA_TYPE a2 = rowm[j+1];
    DATA_TYPE b2 = row [j+1];
    DATA_TYPE c2 = rowp[j+1];
    row[j] = (a0+a1+a2 + b0+b1+b2 + c0+c1+c2) * inv9;
    a0=a1; a1=a2; b0=b1; b1=b2; c0=c1; c1=c2;
  }
}

该形式可减少部分重复访存，但由于 row[j] 原地更新，自动向量化仍受限。

不能直接对 i/j 使用普通 OpenMP parallel for，因为存在同一步内依赖。可按 d=i+j 的波前并行：

for (t = 0; t < tsteps; ++t) {
  for (d = 2; d <= 2*(n-2); ++d) {
    #pragma omp parallel for schedule(static)
    for (i = max(1, d-(n-2)); i <= min(n-2, d-1); ++i) {
      int j = d - i;
      A[i][j] = (A[i-1][j-1] + A[i-1][j] + A[i-1][j+1]
               + A[i][j-1]   + A[i][j]   + A[i][j+1]
               + A[i+1][j-1] + A[i+1][j] + A[i+1][j+1]) * inv9;
    }
  }
}

更高效的实现通常结合 tile-wavefront：先分块，再按 tile 对角线并行，降低同步次数。

若允许改变更新顺序/数值轨迹，推荐双缓冲 Jacobi：

for (t = 0; t < tsteps; ++t) {
  for (i = 1; i < n-1; ++i)
    for (j = 1; j < n-1; ++j)
      B[i][j] = (A[i-1][j-1] + A[i-1][j] + A[i-1][j+1]
               + A[i][j-1]   + A[i][j]   + A[i][j+1]
               + A[i+1][j-1] + A[i+1][j] + A[i+1][j+1]) * inv9;
  swap(A, B);
}

若需保持 Gauss-Seidel 语义更接近，可采用红黑着色：先更新 (i+j)%2==0，再更新 (i+j)%2==1，并在每个颜色阶段并行。
